+			provider: "lmstudio",
+			model: "qwen2.5-coder",
+		});
+		expect(resolveMemoryModel("consolidation", settings, models)).toEqual({
+			provider: "anthropic-main",
+			model: "claude-sonnet-4-6",
+		});
+		expect(resolveMemoryModel("entityGc", settings, models)).toEqual({
+			provider: "lmstudio",
+			model: "qwen2.5-coder",
+		});
