+		expect(() => resolveMemoryModel("extraction", settings, catalog([]))).toThrow(
+			"No memory 'extraction' model is configured",
+		);
+	});
+
+	test("rejects memory refs with unknown or disabled providers", () => {
+		expect(() =>
+			resolveMemoryModel(
+				"extraction",
